using namespace std;

void bubbleSort(vector<int>& a) {
    int n = a.size();
    for (int i = 0; i < n - 1; ++i) {
        for (int j = 0; j < n - i - 1; ++j) {
            if (a[j] > a[j + 1]) swap(a[j], a[j + 1]);
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> arr(N);
        for (int i = 0; i < N; ++i) cin >> arr[i];
        bubbleSort(arr);
        for (int i = 0; i < N; ++i) {
            cout << arr[i];
            if (i + 1 < N) cout << ' ';
        }
        cout << '\n';
    }
    return 0;
}

